// test/integration/core/DiContainer.integration.test.js

const assert = require('assert');
const DiContainer = require('../../../src/core/DiContainer');

describe('DiContainer (Integration)', () => {
  before(() => DiContainer.reset());

  it('should integrate multiple services', () => {
    class Logger {
      log(msg) {
        return `LOG: ${msg}`;
      }
    }

    class App {
      constructor() {
        this.logger = DiContainer.resolve('Logger');
      }

      run() {
        return this.logger.log('Hello');
      }
    }

    DiContainer.register('Logger', Logger);
    DiContainer.register('App', App);

    const app = DiContainer.resolve('App');
    assert.strictEqual(app.run(), 'LOG: Hello');
  });
});